<?php
namespace App\Models;
use App\Enums\AccountType;use App\Models\Concerns\BelongsToTenant;use App\Models\Concerns\HasAuditTrail;use Illuminate\Database\Eloquent\Concerns\HasUlids;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\BelongsTo;use Illuminate\Database\Eloquent\Relations\HasMany;use Illuminate\Database\Eloquent\SoftDeletes;
class LedgerAccount extends Model{use BelongsToTenant,HasAuditTrail,HasUlids,SoftDeletes;protected $fillable=['cooperative_id','parent_id','code','name','type','normal_balance','is_control_account','allows_direct_posting','is_system','is_active','description'];protected function casts():array{return ['type'=>AccountType::class,'is_control_account'=>'boolean','allows_direct_posting'=>'boolean','is_system'=>'boolean','is_active'=>'boolean'];}public function parent():BelongsTo{return $this->belongsTo(self::class,'parent_id');}public function children():HasMany{return $this->hasMany(self::class,'parent_id');}public function lines():HasMany{return $this->hasMany(JournalEntryLine::class);}}
